diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..7df5202bf887 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -909,7 +909,7 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     return BinaryOperator::CreateAdd(X, ConstantExpr::getAdd(Op01C, Op1C));

   // (X | C2) + C --> (X | C2) ^ C2 iff (C2 == -C)
-  const APInt *C2;
+  const APInt *C1, *C2;
   if (match(Op0, m_Or(m_Value(), m_APInt(C2))) && *C2 == -*C)
     return BinaryOperator::CreateXor(Op0, ConstantInt::get(Add.getType(), *C2));

@@ -993,6 +993,24 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     }
   }

+
+  // add (zext nneg (add nsw X, C1)), C2 --> add (sext X), (sext(C1) + C2)
+  // When zext nneg is used, the operand is non-negative and zext == sext.
+  if (match(Op0, m_OneUse(m_ZExt(
+                     m_NSWAdd(m_Value(X), m_APInt(C1)))))) {
+    if (cast<ZExtInst>(Op0)->hasNonNeg()) {
+      unsigned WideBits = Ty->getScalarSizeInBits();
+      APInt NewC = C1->sext(WideBits) + *C;
+      if (NewC.isZero())
+        return CastInst::Create(Instruction::SExt, X, Ty);
+      Value *Sext = Builder.CreateSExt(X, Ty);
+      BinaryOperator *NewAdd = BinaryOperator::CreateAdd(
+          Sext, ConstantInt::get(Ty, NewC));
+      NewAdd->setHasNoSignedWrap(Add.hasNoSignedWrap());
+      return NewAdd;
+    }
+  }
+
   return nullptr;
 }

